import { db, storage } from "/js/firebase-config.js";
import { EnterpriseRepository } from "/js/admin-v4-enterprise-repository.js";
import { ref, uploadBytes, getDownloadURL } from "https://www.gstatic.com/firebasejs/12.0.0/firebase-storage.js";

const SESSION_KEY="mina_admin_api_key_session";
const token=sessionStorage.getItem(SESSION_KEY)||localStorage.getItem(SESSION_KEY)||sessionStorage.getItem("mina_admin_token")||localStorage.getItem("mina_admin_token");
if(!token){location.replace("/admin-login.html?returnUrl=%2Fadmin-v4.html");throw new Error("Chưa đăng nhập");}

const repo=new EnterpriseRepository(db);
const state={posts:[],categories:[],coverFile:null,coverUrl:"",galleryFiles:[],galleryUrls:[],media:[]};
const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];

function slugify(v=""){return v.normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase().replace(/đ/g,"d").replace(/[^a-z0-9]+/g,"-").replace(/(^-|-$)/g,"")}
function esc(v=""){return String(v).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c]))}
function show(msg,type="success"){const n=$("#notice");n.textContent=msg;n.className=`notice ${type}`;n.hidden=false;clearTimeout(show.t);show.t=setTimeout(()=>n.hidden=true,5000)}
function dateText(v){if(!v)return"—";const d=v.toDate?v.toDate():new Date(v);return Number.isNaN(d.getTime())?"—":d.toLocaleString("vi-VN")}
function busy(btn,on,label="Đang xử lý…"){if(on){btn.dataset.old=btn.textContent;btn.textContent=label;btn.disabled=true}else{btn.textContent=btn.dataset.old||btn.textContent;btn.disabled=false}}
function openView(name){$$(".view").forEach(v=>v.classList.toggle("active",v.id===`view-${name}`));$$(".nav-item").forEach(v=>v.classList.toggle("active",v.dataset.view===name));const map={dashboard:"Tổng quan",editor:"Thêm nội dung",posts:"Quản lý nội dung",media:"Media",categories:"Danh mục",settings:"Cài đặt"};$("#pageTitle").textContent=map[name]||"CMS"}
async function upload(file,folder){if(!file.type.startsWith("image/"))throw new Error(`${file.name} không phải ảnh.`);if(file.size>12*1024*1024)throw new Error(`${file.name} vượt quá 12MB.`);const ext=file.name.split(".").pop()?.toLowerCase()||"webp";const name=`${Date.now()}-${Math.random().toString(36).slice(2,7)}-${slugify(file.name.replace(/\.[^.]+$/,""))||"image"}.${ext}`;const r=ref(storage,`${folder}/${name}`);await uploadBytes(r,file,{contentType:file.type});return getDownloadURL(r)}
function renderCover(){const c=$("#coverPreview");c.innerHTML="";const src=state.coverFile?URL.createObjectURL(state.coverFile):state.coverUrl;if(src)c.innerHTML=`<img src="${esc(src)}" alt="">`}
function renderGallery(){const c=$("#galleryPreview");c.innerHTML=[...state.galleryUrls.map((u,i)=>`<div class="media-card"><img src="${esc(u)}"><button class="remove" type="button" data-u="${i}">×</button></div>`),...state.galleryFiles.map((f,i)=>`<div class="media-card"><img src="${URL.createObjectURL(f)}"><button class="remove" type="button" data-f="${i}">×</button></div>`)].join("")}
function rows(items,compact=false){if(!items.length)return`<p class="muted">Chưa có dữ liệu.</p>`;return`<table><thead><tr><th>Nội dung</th><th>Loại</th><th>Trạng thái</th><th>Danh mục</th><th>Cập nhật</th>${compact?"":"<th>Thao tác</th>"}</tr></thead><tbody>${items.map(p=>`<tr><td><strong>${esc(p.title||"(Không tiêu đề)")}</strong><br><small class="muted">${esc(p.internalId||p.slug||p.id)}</small></td><td>${esc(p.contentType||"blog")}</td><td><span class="status ${p.status==="published"?"published":"draft"}">${p.status==="published"?"Đã đăng":"Bản nháp"}</span></td><td>${esc(p.categoryName||"Chưa phân loại")}</td><td>${dateText(p.updatedAt||p.createdAt)}</td>${compact?"":`<td><div class="row-actions"><button class="button small" data-edit="${p.id}">Sửa</button><button class="button small danger" data-delete="${p.id}">Xóa</button></div></td>`}</tr>`).join("")}</tbody></table>`}
function renderPosts(){const q=$("#searchInput").value.trim().toLowerCase(),type=$("#typeFilter").value,status=$("#statusFilter").value;const items=state.posts.filter(p=>(!q||`${p.title||""} ${p.slug||""} ${p.internalId||""}`.toLowerCase().includes(q))&&(!type||(p.contentType||"blog")===type)&&(!status||p.status===status));$("#postsTable").innerHTML=rows(items);$("#recentTable").innerHTML=rows(state.posts.slice(0,10),true)}
function renderStats(){$("#statTotal").textContent=state.posts.length;$("#statPublished").textContent=state.posts.filter(p=>p.status==="published").length;$("#statDraft").textContent=state.posts.filter(p=>p.status!=="published").length;$("#statCategories").textContent=state.categories.length}
function renderCategories(){const s=$("#categoryId"),old=s.value;s.innerHTML=`<option value="">Chưa phân loại</option>`+state.categories.map(c=>`<option value="${c.id}">${esc(c.name||c.categoryName||c.id)}</option>`).join("");s.value=old;$("#categoryList").innerHTML=state.categories.length?state.categories.map(c=>`<div class="category-row"><div><strong>${esc(c.name||c.categoryName||c.id)}</strong><small>${esc(c.slug||"")}</small></div><button class="button small danger" data-delete-category="${c.id}">Xóa</button></div>`).join(""):`<p class="muted">Chưa có danh mục.</p>`}
async function refresh(){[state.posts,state.categories]=await Promise.all([repo.listPosts(),repo.listCategories()]);renderPosts();renderCategories();renderStats()}
function reset(){$("#contentForm").reset();$("#postId").value="";state.coverFile=null;state.coverUrl="";state.galleryFiles=[];state.galleryUrls=[];renderCover();renderGallery();$("#saveButton").textContent="Lưu nội dung"}
function fill(p){reset();$("#postId").value=p.id;$("#contentType").value=p.contentType||"blog";$("#title").value=p.title||"";$("#slug").value=p.slug||"";$("#internalId").value=p.internalId||p.aiId||"";$("#excerpt").value=p.excerpt||p.description||"";$("#content").value=p.content||"";$("#prompt").value=p.prompt||p.aiPrompt||"";$("#smartLinkSlug").value=p.smartLinkSlug||"";$("#destinationUrl").value=p.destinationUrl||"";$("#status").value=p.status||"draft";$("#categoryId").value=p.categoryId||"";$("#featured").checked=!!p.featured;$("#seoTitle").value=p.seoTitle||"";$("#seoDescription").value=p.seoDescription||"";state.coverUrl=p.coverImage||p.image||p.thumbnail||"";state.galleryUrls=Array.isArray(p.gallery)?[...p.gallery]:[];renderCover();renderGallery();$("#saveButton").textContent="Cập nhật nội dung";openView("editor")}
async function confirmBox(title,msg){const d=$("#confirmDialog");$("#confirmTitle").textContent=title;$("#confirmMessage").textContent=msg;d.showModal();return new Promise(r=>d.addEventListener("close",()=>r(d.returnValue==="confirm"),{once:true}))}

$$(".nav-item").forEach(b=>b.onclick=()=>openView(b.dataset.view));$$("[data-open]").forEach(b=>b.onclick=()=>openView(b.dataset.open));$("#quickAdd").onclick=()=>{reset();openView("editor")};$("#newButton").onclick=reset;
$("#logoutButton").onclick=()=>{[sessionStorage,localStorage].forEach(s=>{s.removeItem(SESSION_KEY);s.removeItem("mina_admin_authenticated");s.removeItem("mina_admin_token");s.removeItem("mina_admin_key")});location.replace("/admin-login.html")};
$("#title").oninput=()=>{if(!$("#postId").value&&!$("#slug").dataset.touched)$("#slug").value=slugify($("#title").value)};$("#slug").oninput=()=>$("#slug").dataset.touched="1";
$("#coverPick").onclick=()=>$("#coverInput").click();$("#coverInput").onchange=e=>{state.coverFile=e.target.files?.[0]||null;renderCover()};
$("#galleryPick").onclick=()=>$("#galleryInput").click();$("#galleryInput").onchange=e=>{state.galleryFiles.push(...[...(e.target.files||[])]);renderGallery()};$("#galleryPreview").onclick=e=>{if(e.target.dataset.u!==undefined)state.galleryUrls.splice(+e.target.dataset.u,1);if(e.target.dataset.f!==undefined)state.galleryFiles.splice(+e.target.dataset.f,1);renderGallery()};
$("#contentForm").onsubmit=async e=>{e.preventDefault();const btn=$("#saveButton");busy(btn,true,"Đang lưu…");try{const title=$("#title").value.trim();if(!title)throw new Error("Bạn chưa nhập tiêu đề.");let cover=state.coverUrl,gallery=[...state.galleryUrls];if(state.coverFile)cover=await upload(state.coverFile,"cms-v4-enterprise/covers");if(state.galleryFiles.length)gallery.push(...await Promise.all(state.galleryFiles.map(f=>upload(f,"cms-v4-enterprise/galleries"))));const cat=state.categories.find(c=>c.id===$("#categoryId").value),excerpt=$("#excerpt").value.trim(),smartSlug=$("#smartLinkSlug").value.trim();const payload={contentType:$("#contentType").value,title,slug:$("#slug").value.trim()||slugify(title),internalId:$("#internalId").value.trim(),excerpt,description:excerpt,content:$("#content").value.trim(),prompt:$("#prompt").value.trim(),smartLinkSlug:smartSlug,destinationUrl:$("#destinationUrl").value.trim(),smartLinkPath:smartSlug?`/go/${smartSlug}`:"",status:$("#status").value,categoryId:cat?.id||"",categoryName:cat?.name||cat?.categoryName||"",category:cat?.name||cat?.categoryName||"",featured:$("#featured").checked,coverImage:cover,image:cover,thumbnail:cover,gallery,seoTitle:$("#seoTitle").value.trim()||title,seoDescription:$("#seoDescription").value.trim()||excerpt.slice(0,160),publishedAt:$("#status").value==="published"?new Date().toISOString():null};const id=await repo.savePost(payload,$("#postId").value);$("#postId").value=id;state.coverFile=null;state.coverUrl=cover;state.galleryFiles=[];state.galleryUrls=gallery;await refresh();show("Đã lưu nội dung thành công.")}catch(err){console.error(err);show(err.message||"Không thể lưu nội dung.","error")}finally{busy(btn,false)}};
["searchInput","typeFilter","statusFilter"].forEach(id=>$("#"+id).addEventListener(id==="searchInput"?"input":"change",renderPosts));
$("#postsTable").onclick=async e=>{if(e.target.dataset.edit){try{fill(await repo.getPost(e.target.dataset.edit))}catch(err){show(err.message,"error")}}if(e.target.dataset.delete&&await confirmBox("Xóa nội dung","Hành động này không thể hoàn tác.")){try{await repo.deletePost(e.target.dataset.delete);await refresh();show("Đã xóa nội dung.")}catch(err){show(err.message,"error")}}};
$("#categoryName").oninput=()=>{if(!$("#categorySlug").dataset.touched)$("#categorySlug").value=slugify($("#categoryName").value)};$("#categorySlug").oninput=()=>$("#categorySlug").dataset.touched="1";
$("#categoryForm").onsubmit=async e=>{e.preventDefault();try{const name=$("#categoryName").value.trim();await repo.saveCategory({name,categoryName:name,slug:$("#categorySlug").value.trim()||slugify(name),description:$("#categoryDescription").value.trim()});e.target.reset();await refresh();show("Đã thêm danh mục.")}catch(err){show(err.message,"error")}};
$("#categoryList").onclick=async e=>{const id=e.target.dataset.deleteCategory;if(id&&await confirmBox("Xóa danh mục","Nội dung hiện có sẽ không bị xóa.")){try{await repo.deleteCategory(id);await refresh();show("Đã xóa danh mục.")}catch(err){show(err.message,"error")}}};
$("#mediaPick").onclick=()=>$("#mediaInput").click();$("#mediaInput").onchange=async e=>{const files=[...(e.target.files||[])],btn=$("#mediaPick");if(!files.length)return;busy(btn,true,`Đang upload ${files.length} ảnh…`);try{state.media.unshift(...await Promise.all(files.map(f=>upload(f,"cms-v4-enterprise/media"))));$("#mediaLibrary").innerHTML=state.media.map(u=>`<div class="media-card"><img src="${esc(u)}"><div class="actions"><button class="button small" data-copy="${esc(u)}">Copy URL</button></div></div>`).join("");show(`Đã upload ${files.length} ảnh.`)}catch(err){show(err.message,"error")}finally{busy(btn,false);e.target.value=""}};
$("#mediaLibrary").onclick=async e=>{if(e.target.dataset.copy){await navigator.clipboard.writeText(e.target.dataset.copy);show("Đã copy URL ảnh.")}};
$("#settingsForm").onsubmit=async e=>{e.preventDefault();try{await repo.saveSettings({siteName:$("#siteName").value.trim(),siteUrl:$("#siteUrl").value.trim(),defaultAuthor:$("#defaultAuthor").value.trim()});show("Đã lưu cài đặt.")}catch(err){show(err.message,"error")}};

$("#sessionBadge").textContent="Đã đăng nhập";
try{await refresh();const s=await repo.loadSettings();if(s.siteName)$("#siteName").value=s.siteName;if(s.siteUrl)$("#siteUrl").value=s.siteUrl;if(s.defaultAuthor)$("#defaultAuthor").value=s.defaultAuthor}catch(err){console.error(err);show("CMS đã mở nhưng chưa đọc được dữ liệu. Hãy kiểm tra Firestore Rules.","error")}
